import datetime
import matplotlib.pyplot as plt
import pandas as pd
import numpy as np

class Workout:
    def __init__(self, date, sport, duration, distance=None, calories=None, heart_rate_data=None, other_data=None):
        self.date = date
        self.sport = sport
        self.duration = duration  # in minutes
        self.distance = distance  # in km
        self.calories = calories
        self.heart_rate_data = heart_rate_data  # list of (timestamp, heart_rate) tuples
        self.other_data = other_data or {}

    def __repr__(self):
        return f"Workout({self.date}, {self.sport}, {self.duration} min, {self.distance} km)"

class Nutrition:
    def __init__(self, date, calories, protein, carbs, fat):
        self.date = date
        self.calories = calories
        self.protein = protein
        self.carbs = carbs
        self.fat = fat

    def __repr__(self):
        return f"Nutrition({self.date}, {self.calories} kcal)"

class UserProfile:
    def __init__(self, name):
        self.name = name
        self.workouts = []
        self.nutrition_data = []

    def add_workout(self, workout):
        self.workouts.append(workout)

    def add_nutrition_data(self, nutrition):
