    def import_strava_data(self, strava_file):
        # Placeholder for Strava import logic
        # This would involve parsing the Strava data file (e.g., CSV, TCX, GPX)
        # and creating Workout objects.
        print(f"Importing Strava data from {strava_file} (placeholder)")
        # Example:
        # self.add_workout(Workout(date=datetime.date(2024, 1, 1), sport="Running", duration=30, distance=5))

    def import_polar_data(self, polar_file):
        # Placeholder for Polar import logic
        print(f"Importing Polar data from {polar_file} (placeholder)")

    def import_myfitnesspal_data(self, mfp_file):
        # Placeholder for MyFitnessPal import logic
        print(f"Importing MyFitnessPal data from {mfp_file} (placeholder)")

    def filter_workouts(self, sport=None, start_date=None, end_date=None):
        filtered_workouts = self.workouts[:]
        if sport:
            filtered_workouts = [w for w in filtered_workouts if w.sport == sport]
        if start_date:
            filtered_workouts = [w for w in filtered_workouts if w.date >= start_date]
        if end_date:
            filtered_workouts = [w for w in filtered_workouts if w.date <= end_date]
        return filtered_workouts

    def aggregate_heart_rate_zones(self, workouts=None):
        if workouts is None:
            workouts = self.workouts
        zones = {"Zone 1": 0, "Zone 2": 0, "Zone 3": 0, "Zone 4": 0, "Zone 5": 0}
        for workout in workouts:
            if workout.heart_rate_data:
                for timestamp, hr in workout.heart_rate_data:
                    # Example zones (adjust as needed)
                    if hr < 120:
                        zones["Zone 1"] += 1  # Assuming 1 second intervals
                    elif hr < 140:
                        zones["Zone 2"] += 1
                    elif hr < 160:
                        zones["Zone 3"] += 1
                    elif hr < 180:
                        zones["Zone 4"] += 1
                    else:
                        zones["Zone 5"] += 1
        return zones

    def calculate_pace(self, workout):
        if workout.distance and workout.duration:
            return workout.duration / workout.distance
        return None

    def generate_progress_plot(self, metric="distance", sport=None):
        dates = []
        values = []

        filtered_workouts = self.filter_workouts(sport=sport)

        if metric == "distance":
            for workout in filtered_workouts:
                dates.append(workout.date)
                values.append(workout.distance or 0)
            ylabel = "Distance (km)"
        elif metric == "pace":
            for workout in filtered_workouts:
                pace = self.calculate_pace(workout)
                if pace:
                    dates.append(workout.date)
                    values.append(pace)
            ylabel = "Pace (min/km)"
        else:
            print("Invalid metric.")
            return

        if not dates:
            print("No data available for the selected metric and sport.")
            return

        plt.figure(figsize=(10, 6))
        plt.plot(dates, values, marker='o')
        plt.xlabel("Date")
        plt.ylabel(ylabel)
        plt.title(f"Progress Tracking ({metric.capitalize()})")
        plt.grid(True)
        plt.xticks(rotation=45)
        plt.tight_layout()
        plt.show()

    def generate_dashboard(self, sport=None):
        workouts = self.filter_workouts(sport=sport)
        total_distance = sum(w.distance or 0 for w in workouts)
        total_duration = sum(w.duration for w in workouts)
        heart_rate_zones = self.aggregate_heart_rate_zones(workouts)

        print(f"Dashboard for {self.name} (Sport: {sport or 'All'})")
        print(f"Total Distance: {total_distance:.2f} km")
        print(f"Total Duration: {total_duration:.2f} minutes")
        print("Heart Rate Zones:")
        for zone, time in heart_rate_zones.items():
            print(f"  {zone}: {time} seconds")

