                    print(f"Error importing Strava data: {e}. Skipping activity.")
            else:
                print("Incomplete Strava data. Skipping activity.")

    def import_polar_flow(self, polar_flow_data):
        """Imports workout data from Polar Flow. Polar Flow data should be a list of dictionaries."""
        for activity in polar_flow_data:
            if 'sport' in activity and 'distance' in activity and 'startTime' in activity:
                try:
                    activity['distance'] = float(activity['distance']) / 1000  # Convert meters to km
                    activity['start_date_local'] = datetime.datetime.strptime(activity['startTime'], '%Y-%m-%dT%H:%M:%S.%fZ')
                    self.data['workouts'].append(activity)
                except (ValueError, TypeError) as e:
                    print(f"Error importing Polar Flow data: {e}. Skipping activity.")
            else:
                print("Incomplete Polar Flow data. Skipping activity.")

    def import_myfitnesspal(self, myfitnesspal_data):
        """Imports nutrition data from MyFitnessPal. MyFitnessPal data should be a list of dictionaries."""
        for entry in myfitnesspal_data:
            if 'date' in entry and 'calories' in entry:
                try:
                    entry['date'] = datetime.datetime.strptime(entry['date'], '%Y-%m-%d')
                    entry['calories'] = int(entry['calories'])
                    self.data['nutrition'].append(entry)
                except (ValueError, TypeError) as e:
                    print(f"Error importing MyFitnessPal data: {e}. Skipping entry.")
            else:
                print("Incomplete MyFitnessPal data. Skipping entry.")

    def filter_workouts(self, sport=None, start_date=None, end_date=None):
        """Filters workouts based on sport and date range."""
        filtered_workouts = self.data['workouts']
        if sport:
            filtered_workouts = [w for w in filtered_workouts if w.get('type', w.get('sport')) == sport] #Handles both Strava and Polar Flow
        if start_date:
            filtered_workouts = [w for w in filtered_workouts if w['start_date_local'].date() >= start_date]
        if end_date:
            filtered_workouts = [w for w in filtered_workouts if w['start_date_local'].date() <= end_date]
        return filtered_workouts

    def aggregate_heart_rate_zones(self, workouts):
        """Aggregates time spent in different heart rate zones."""
        heart_rate_zones = {}
        for workout in workouts:
            if 'heartrate_zones' in workout:  # Assuming heartrate_zones is a list of dicts
                for zone in workout['heartrate_zones']:
                    zone_name = zone.get('zone', 'Unknown')
                    duration = zone.get('duration', 0)  # Duration in seconds
                    if zone_name in heart_rate_zones:
                        heart_rate_zones[zone_name] += duration
                    else:
                        heart_rate_zones[zone_name] = duration

        # Convert seconds to hours for better readability
        for zone in heart_rate_zones:
            heart_rate_zones[zone] = heart_rate_zones[zone] / 3600

        return heart_rate_zones

    def calculate_pace(self, workout):
        """Calculates pace in minutes per kilometer."""
        if 'distance' in workout and 'elapsed_time' in workout:
            distance_km = workout['distance']
            elapsed_time_seconds = workout['elapsed_time']
            if distance_km > 0 and elapsed_time_seconds > 0:
                pace_seconds_per_km = elapsed_time_seconds / distance_km
                pace_minutes_per_km = pace_seconds_per_km / 60
                return pace_minutes_per_km
        return None

    def generate_progress_graph(self, data_type='distance', sport=None):
