                date = workout['start_date_local'].date()
                if date in daily_distances:
                    daily_distances[date] += workout['distance']
                else:
                    daily_distances[date] = workout['distance']

            distances = [daily_distances.get(date, 0) for date in dates] #Handle missing dates

            plt.figure(figsize=(12, 6))
            plt.plot(dates, distances, marker='o')
            plt.xlabel("Date")
            plt.ylabel("Distance (km)")
            plt.title("Progress by Distance")
            plt.grid(True)
            plt.xticks(rotation=45)
            plt.tight_layout()
            plt.show()

        elif data_type == 'pace':
            daily_paces = {}
            for date in dates:
                paces_for_date = []
                total_distance = 0
                for workout in workouts:
                    if workout['start_date_local'].date() == date:
                        pace = self.calculate_pace(workout)
                        if pace is not None:
                            paces_for_date.append(pace)
                            total_distance += workout['distance']

