import pandas as pd
import numpy as np

class PhysicalExertionTracker:
    def __init__(self):
        self.data = {}  # Store data from different apps
        self.aggregated_data = pd.DataFrame() # Store aggregated data
        self.intensity_zones = {
            "Zone 1": (0.5, 0.6),  # Example heart rate zones (fraction of max HR)
            "Zone 2": (0.6, 0.7),
            "Zone 3": (0.7, 0.8),
            "Zone 4": (0.8, 0.9),
            "Zone 5": (0.9, 1.0),
        }
        self.max_heart_rate = 190 # Example max heart rate

    def import_strava(self, strava_data):
        # Placeholder for Strava data import logic
        # Assume strava_data is a list of dictionaries, each representing an activity
        # Example: [{'date': '2024-01-01', 'sport': 'running', 'distance': 5.0, 'time': 30, 'heart_rate': [150, 155, 160]}, ...]
        self.data['strava'] = strava_data
        self.aggregate_data()

    def import_polar_flow(self, polar_data):
        # Placeholder for Polar Flow data import logic
        # Assume polar_data is a list of dictionaries, each representing an activity
        self.data['polar'] = polar_data
        self.aggregate_data()

    def import_myfitnesspal(self, mfp_data):
        # Placeholder for MyFitnessPal data import logic
        # Assume mfp_data is a list of dictionaries, each representing daily nutrition
        self.data['myfitnesspal'] = mfp_data
        self.aggregate_data()

    def aggregate_data(self):
        all_activities = []
        for app, activities in self.data.items():
            if isinstance(activities, list):
                for activity in activities:
                    activity['source'] = app  # Add source app for tracking
                    all_activities.append(activity)

        self.aggregated_data = pd.DataFrame(all_activities)

        if not self.aggregated_data.empty:
            if 'date' in self.aggregated_data.columns:
                try:
                    self.aggregated_data['date'] = pd.to_datetime(self.aggregated_data['date'])
                except:
                    print("Error converting date column. Ensure date format is consistent.")

    def calculate_intensity_zones(self, heart_rate_data):
        """Calculates time spent in each heart rate zone."""
        zone_times = {zone: 0 for zone in self.intensity_zones}
        total_time = len(heart_rate_data)
        if total_time == 0:
            return zone_times

        for hr in heart_rate_data:
            hr_fraction = hr / self.max_heart_rate
            for zone, (lower, upper) in self.intensity_zones.items():
                if lower <= hr_fraction <= upper:
                    zone_times[zone] += 1

        # Convert counts to time (assuming each HR reading is 1 second)
        for zone in zone_times:
            zone_times[zone] = zone_times[zone] #* 1  # Time in seconds

        return zone_times

    def get_heart_rate_zone_summary(self):
        """Aggregates heart rate zone data across all activities."""
        zone_summary = {zone: 0 for zone in self.intensity_zones}

        if not self.aggregated_data.empty and 'heart_rate' in self.aggregated_data.columns:
            for index, row in self.aggregated_data.iterrows():
                if isinstance(row['heart_rate'], list):
                    zone_times = self.calculate_intensity_zones(row['heart_rate'])
                    for zone, time in zone_times.items():
                        zone_summary[zone] += time

        return zone_summary

    def create_dashboard(self):
        """Creates a text-based dashboard (can be extended with GUI)."""
        print("--- Physical Exertion Dashboard ---")

        if not self.aggregated_data.empty:
            print("\nRecent Activities:")
            print(self.aggregated_data[['date', 'sport', 'distance', 'source']].tail())

            print("\nHeart Rate Zone Summary:")
            zone_summary = self.get_heart_rate_zone_summary()
            for zone, time in zone_summary.items():
                print(f"{zone}: {time} seconds")

            self.plot_progress()
        else:
            print("No data available. Please import data from fitness apps.")

    def plot_progress(self, metric='distance'):
        """Plots overall progress by distance or pace."""
        if self.aggregated_data.empty:
            print("No data to plot.")
            return

        if 'date' not in self.aggregated_data.columns:
            print("Date column not found. Cannot plot progress.")
            return

        if metric == 'distance' and 'distance' in self.aggregated_data.columns:
            data_to_plot = self.aggregated_data.groupby('date')['distance'].sum()
            plt.figure(figsize=(10, 6))
            plt.plot(data_to_plot.index, data_to_plot.values)
            plt.xlabel("Date")
            plt.ylabel("Total Distance")
            plt.title("Overall Progress by Distance")
            plt.grid(True)
            plt.show()

        elif metric == 'pace' and 'time' in self.aggregated_data.columns and 'distance' in self.aggregated_data.columns:
