        self.calories = calories
        self.protein = protein
        self.carbs = carbs
        self.fat = fat

    def __repr__(self):
        return f"Nutrition({self.date}, {self.calories}, {self.protein}, {self.carbs}, {self.fat})"


class FitnessTracker:
    def __init__(self):
        self.workouts = []
        self.nutrition_data = []
        self.custom_metrics = {}  # Store user-defined metrics

    def import_data(self, data_source, data):
        """
        Imports data from various fitness apps.
        Data should be a list of dictionaries or objects that can be converted to Workout/Nutrition objects.
        """
        if data_source == "Strava":
            for item in data:
                # Assuming Strava data has keys like 'date', 'duration', 'type', 'distance', 'calories', 'heart_rate'
                try:
                    date = datetime.datetime.strptime(item['date'], '%Y-%m-%d').date()
                    self.workouts.append(
                        Workout(date, item['duration'], item['type'], item['distance'], item['calories'], item['heart_rate'])
                    )
                except (KeyError, ValueError) as e:
                    print(f"Error importing Strava data: {e}. Skipping entry.")

        elif data_source == "Polar Flow":
            for item in data:
                # Assuming Polar Flow data has keys like 'date', 'duration', 'sport', 'distance', 'calories', 'heart_rate'
                try:
                    date = datetime.datetime.strptime(item['date'], '%Y-%m-%d').date()
                    self.workouts.append(
                        Workout(date, item['duration'], item['sport'], item['distance'], item['calories'], item['heart_rate'])
                    )
                except (KeyError, ValueError) as e:
                    print(f"Error importing Polar Flow data: {e}. Skipping entry.")

        elif data_source == "MyFitnessPal":
            for item in data:
                # Assuming MyFitnessPal data has keys like 'date', 'calories', 'protein', 'carbs', 'fat'
                try:
                    date = datetime.datetime.strptime(item['date'], '%Y-%m-%d').date()
                    self.nutrition_data.append(
                        Nutrition(date, item['calories'], item['protein'], item['carbs'], item['fat'])
                    )
                except (KeyError, ValueError) as e:
                    print(f"Error importing MyFitnessPal data: {e}. Skipping entry.")
        else:
            print(f"Unsupported data source: {data_source}")

    def add_workout(self, workout):
        self.workouts.append(workout)

    def add_nutrition_data(self, nutrition):
        self.nutrition_data.append(nutrition)

    def calculate_total_distance(self, sport=None, start_date=None, end_date=None):
        """Calculates total distance for a given sport (or all sports) within a date range."""
        total_distance = 0
        for workout in self.workouts:
            if (sport is None or workout.sport == sport) and \
               (start_date is None or workout.date >= start_date) and \
               (end_date is None or workout.date <= end_date) and \
               workout.distance is not None:
                total_distance += workout.distance
        return total_distance

    def calculate_total_calories_burned(self, sport=None, start_date=None, end_date=None):
        """Calculates total calories burned for a given sport (or all sports) within a date range."""
        total_calories = 0
        for workout in self.workouts:
            if (sport is None or workout.sport == sport) and \
               (start_date is None or workout.date >= start_date) and \
               (end_date is None or workout.date <= end_date) and \
               workout.calories is not None:
                total_calories += workout.calories
        return total_calories

    def calculate_heart_rate_zones(self):
        """Calculates time spent in different heart rate zones."""
        zones = {
            "Zone 1 (Warm-up)": 0,  # 50-60% of max HR
            "Zone 2 (Fat Burning)": 0,  # 60-70% of max HR
            "Zone 3 (Cardio)": 0,  # 70-80% of max HR
            "Zone 4 (Threshold)": 0,  # 80-90% of max HR
            "Zone 5 (Maximum)": 0,  # 90-100% of max HR
        }

        for workout in self.workouts:
            if workout.heart_rate_data:
                for i in range(len(workout.heart_rate_data) - 1):
                    timestamp1, hr1 = workout.heart_rate_data[i]
                    timestamp2, hr2 = workout.heart_rate_data[i+1]
                    time_diff = (timestamp2 - timestamp1).total_seconds() / 60  # in minutes

                    # Assuming max HR is 220 - age (a very rough estimate)
                    max_hr = 220 - 30  # Assuming age 30 for example
                    if hr1 is not None:
                        percentage = hr1 / max_hr

                        if 0.5 <= percentage < 0.6:
                            zones["Zone 1 (Warm-up)"] += time_diff
                        elif 0.6 <= percentage < 0.7:
                            zones["Zone 2 (Fat Burning)"] += time_diff
                        elif 0.7 <= percentage < 0.8:
                            zones["Zone 3 (Cardio)"] += time_diff
                        elif 0.8 <= percentage < 0.9:
                            zones["Zone 4 (Threshold)"] += time_diff
                        elif 0.9 <= percentage <= 1.0:
                            zones["Zone 5 (Maximum)"] += time_diff

        return zones

    def get_nutrition_summary(self, start_date=None, end_date=None):
        """Calculates total calories, protein, carbs, and fat within a date range."""
        total_calories = 0
        total_protein = 0
        total_carbs = 0
        total_fat = 0

        for nutrition in self.nutrition_data:
            if (start_date is None or nutrition.date >= start_date) and \
               (end_date is None or nutrition.date <= end_date):
                total_calories += nutrition.calories
                total_protein += nutrition.protein
                total_carbs += nutrition.carbs
                total_fat += nutrition.fat

        return {
            "calories": total_calories,
            "protein": total_protein,
            "carbs": total_carbs,
            "fat": total_fat,
        }

    def define_custom_metric(self, name, calculation_function):
        """Defines a custom metric using a function that takes the FitnessTracker object as input."""
        self.custom_metrics[name] = calculation_function

    def calculate_custom_metric(self, name):
        """Calculates a custom metric."""
        if name in self.custom_metrics:
            return self.custom_metrics[name](self)
        else:
            return None

    def plot_progress(self, metric="distance"):
        """Plots progress over time for a given metric (distance or calories)."""
        dates = []
        values = []

        if metric == "distance":
            # Aggregate distance by date
            daily_distances = {}
            for workout in self.workouts:
                if workout.distance is not None:
                    if workout.date in daily_distances:
                        daily_distances[workout.date] += workout.distance
                    else:
                        daily_distances[workout.date] = workout.distance

            dates = sorted(daily_distances.keys())
            values = [daily_distances[date] for date in dates]

        elif metric == "calories":
            # Aggregate calories burned by date
            daily_calories = {}
            for workout in self.workouts:
                if workout.calories is not None:
                    if workout.date in daily_calories:
                        daily_calories[workout.date] += workout.calories
                    else:
                        daily_calories[workout.date] = workout.calories

            dates = sorted(daily_calories.keys())
            values = [daily_calories[date] for date in dates]

        else:
            print("Unsupported metric for plotting.")
            return

        if dates and values:
            plt.plot(dates, values)
            plt.xlabel("Date")
            plt.ylabel(metric.capitalize())
            plt.title(f"Progress Over Time ({metric.capitalize()})")
            plt.xticks(rotation=45)
            plt.tight_layout()
            plt.show()
        else:
            print("No data available to plot for the selected metric.")


