class WorkoutApp:
    def __init__(self):
        self.data = {}
        self.data['workouts'] = []
        self.data['nutrition'] = []

    def import_strava(self, strava_data):
        """Imports workout data from Strava.  Strava data should be a list of dictionaries."""
        for workout in strava_data:
            workout['source'] = 'Strava'
            self.data['workouts'].append(workout)

    def import_polar_flow(self, polar_data):
        """Imports workout data from Polar Flow. Polar data should be a list of dictionaries."""
        for workout in polar_data:
            workout['source'] = 'Polar Flow'
            self.data['workouts'].append(workout)

    def import_myfitnesspal(self, nutrition_data):
        """Imports nutrition data from MyFitnessPal. Nutrition data should be a list of dictionaries."""
        for entry in nutrition_data:
            entry['source'] = 'MyFitnessPal'
            self.data['nutrition'].append(entry)

    def filter_workouts_by_sport(self, sport):
        """Filters workouts by sport."""
        return [workout for workout in self.data['workouts'] if workout.get('sport') == sport]

    def calculate_total_mileage(self, sport=None):
        """Calculates total mileage, optionally filtered by sport."""
        if sport:
            workouts = self.filter_workouts_by_sport(sport)
        else:
            workouts = self.data['workouts']
        total_mileage = sum([workout.get('distance', 0) for workout in workouts])
        return total_mileage

    def calculate_total_time(self, sport=None):
        """Calculates total time spent exercising, optionally filtered by sport."""
        if sport:
            workouts = self.filter_workouts_by_sport(sport)
        else:
            workouts = self.data['workouts']
        total_time = sum([workout.get('duration', 0) for workout in workouts])
        return total_time

    def calculate_heart_rate_zones(self):
        """Calculates time spent in different heart rate zones."""
        heart_rate_zones = {}
        for workout in self.data['workouts']:
            if 'heart_rate_data' in workout:
                for hr_data in workout['heart_rate_data']:
                    zone = hr_data.get('zone', 'Unknown')
                    duration = hr_data.get('duration', 0)
                    if zone not in heart_rate_zones:
                        heart_rate_zones[zone] = 0
                    heart_rate_zones[zone] += duration
        return heart_rate_zones

    def visualize_progress(self, metric='distance'):
        """Visualizes progress over time by distance or steps."""
        dates = []
        values = []

        if metric == 'distance':
            for workout in self.data['workouts']:
                if 'distance' in workout and 'date' in workout:
                    dates.append(datetime.datetime.strptime(workout['date'], '%Y-%m-%d'))
                    values.append(workout['distance'])
        elif metric == 'steps':
            for workout in self.data['workouts']:
                if 'steps' in workout and 'date' in workout:
                    dates.append(datetime.datetime.strptime(workout['date'], '%Y-%m-%d'))
                    values.append(workout['steps'])
        else:
            print("Invalid metric. Choose 'distance' or 'steps'.")
            return

        if not dates:
            print("No data available for the selected metric.")
            return

        df = pd.DataFrame({'Date': dates, metric: values})
        df = df.groupby('Date')[metric].sum().reset_index()
        df = df.sort_values('Date')

        plt.figure(figsize=(10, 6))
        plt.plot(df['Date'], df[metric])
        plt.xlabel("Date")
        plt.ylabel(metric.capitalize())
        plt.title(f"Progress Over Time ({metric.capitalize()})")
        plt.grid(True)
        plt.show()

    def display_dashboard(self):
        """Displays a summary dashboard of workout and nutrition information."""
        print("--- Workout Dashboard ---")
        print(f"Total Workouts: {len(self.data['workouts'])}")
        print(f"Total Mileage: {self.calculate_total_mileage()} miles")
        print(f"Total Time Exercising: {self.calculate_total_time()} seconds")

        print("\n--- Heart Rate Zone Summary ---")
        heart_rate_zones = self.calculate_heart_rate_zones()
        for zone, duration in heart_rate_zones.items():
            print(f"Zone {zone}: {duration} seconds")

        print("\n--- Nutrition Summary ---")
