class FitnessDashboard:
    def __init__(self, connectors):
        self.connectors = connectors
        self.workouts = []
        self.nutrition = []
        self.load_data()

    def load_data(self):
        for connector in self.connectors:
            self.workouts.extend(connector.fetch_workouts())
            self.nutrition.extend(connector.fetch_nutrition())

        self.workouts_df = pd.DataFrame(self.workouts)
        if not self.workouts_df.empty:
            self.workouts_df['date'] = pd.to_datetime(self.workouts_df['date'])
        self.nutrition_df = pd.DataFrame(self.nutrition)
        if not self.nutrition_df.empty:
            self.nutrition_df['date'] = pd.to_datetime(self.nutrition_df['date'])

    def filter_workouts(self, sport=None, start_date=None, end_date=None):
        """Filters workouts by sport and date range."""
        filtered_df = self.workouts_df.copy()
        if sport:
            filtered_df = filtered_df[filtered_df['sport'] == sport]
        if start_date:
            filtered_df = filtered_df[filtered_df['date'] >= pd.to_datetime(start_date)]
        if end_date:
            filtered_df = filtered_df[filtered_df['date'] <= pd.to_datetime(end_date)]
        return filtered_df

    def aggregate_pace_data(self):
        """Aggregates pace data into pace zones."""
        pace_zones = {
            "Easy": (0, 7.0),  # Minutes per mile
            "Tempo": (7.0, 6.0),
            "Interval": (6.0, 5.0),
            "Race": (5.0, 0)
        }
        pace_zone_times = {zone: 0 for zone in pace_zones}

        for _, workout in self.workouts_df.iterrows():
            if 'pace_data' in workout and workout['pace_data']:
                for i in range(len(workout['pace_data']) - 1):
                    timestamp1, pace1 = workout['pace_data'][i]
                    timestamp2, pace2 = workout['pace_data'][i+1]
                    duration = timestamp2 - timestamp1

                    for zone, (max_pace, min_pace) in pace_zones.items():
                        if min_pace <= pace1 <= max_pace:
                            pace_zone_times[zone] += duration

        return pace_zone_times

    def plot_progress(self, metric='distance'):
        """Plots overall progress by distance or calories."""
        if self.workouts_df.empty:
            print("No workout data available.")
            return

        if metric not in ['distance', 'calories']:
            raise ValueError("Metric must be 'distance' or 'calories'")

        # Group by date and sum the metric
        progress_data = self.workouts_df.groupby('date')[metric].sum()

        plt.figure(figsize=(10, 6))
        plt.plot(progress_data.index, progress_data.values)
        plt.xlabel("Date")
        plt.ylabel(metric.capitalize())
        plt.title(f"Overall Progress by {metric.capitalize()}")
        plt.grid(True)
        plt.show()

    def get_sports_list(self):
        """Returns a list of unique sports."""
        if self.workouts_df.empty:
            return []
        return self.workouts_df['sport'].unique().tolist()

    def display_summary(self):
        """Displays a summary of workout and nutrition data."""
        print("Workout Summary:")
        if not self.workouts_df.empty:
            print(self.workouts_df.describe())
        else:
            print("No workout data available.")

        print("\nNutrition Summary:")
        if not self.nutrition_df.empty:
            print(self.nutrition_df.describe())
        else:
            print("No nutrition data available.")


