class ExerciseDashboardApp:
    def __init__(self):
        self.fitness_apps = {
            "Strava": FitnessAppConnector("Strava"),
            "Polar Flow": FitnessAppConnector("Polar Flow"),
        }
        self.nutrition_apps = {
            "MyFitnessPal": NutritionAppConnector("MyFitnessPal"),
        }
        self.workout_data = []
        self.nutrition_data = []
        self.start_date = None
        self.end_date = None

    def connect_apps(self, fitness_app_names, nutrition_app_names, start_date, end_date):
        self.start_date = start_date
        self.end_date = end_date
        for app_name in fitness_app_names:
            if app_name in self.fitness_apps:
                self.workout_data.extend(self.fitness_apps[app_name].get_workout_data(start_date, end_date))
            else:
                print(f"Error: Fitness app '{app_name}' not supported.")
        for app_name in nutrition_app_names:
            if app_name in self.nutrition_apps:
                self.nutrition_data.extend(self.nutrition_apps[app_name].get_nutrition_data(start_date, end_date))
            else:
                print(f"Error: Nutrition app '{app_name}' not supported.")

    def filter_workouts_by_activity(self, activity_types):
