            return {}

        total_time_in_zones = {zone: 0 for zone in ["Zone 1", "Zone 2", "Zone 3", "Zone 4", "Zone 5"]}
        for workout in self.workout_data:
            for zone, time in workout["heart_rate_zones"].items():
                total_time_in_zones[zone] += time
        return total_time_in_zones

    def generate_progress_graph(self, metric="calories_burned"):
